def test_tc_gw_s01_002_doorfl_stays_open(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    for msg in msgs:
        assert decode_door_fl(msg) == 1

def test_tc_gw_s01_003_doorfl_periodic(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    assert len(msgs) > 1
    for msg in msgs:
        assert decode_door_fl(msg) == 1

def test_tc_gw_s01_004_doorfl_immediate(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    assert decode_door_fl(msgs[0]) == 1

def test_tc_gw_s01_005_doorfl_deterministic(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    reference = decode_door_fl(msgs[0])
    for msg in msgs:
        assert decode_door_fl(msg) == reference

